1	package cmd
2	
3	import (
4		"crypto/rand"
5		"encoding/hex"
6		"encoding/json"
7		"fmt"
8		"io"
9		"os"
10		"strings"
11		"time"
12	
13		"tq/store"
14	
15		"github.com/spf13/cobra"
16	)
17	
18	var (
19		addCmd    string
20		addPri    int
21		addDepStr string
22	)
23	
24	func init() {
25		addCommand.Flags().StringVar(&addCmd, "cmd", "", "Shell command to execute (required)")
26		addCommand.Flags().IntVar(&addPri, "priority", 0, "Task priority (higher = more important)")
27		addCommand.Flags().StringVar(&addDepStr, "depends-on", "", "Comma-separated task IDs")
28		rootCmd.AddCommand(addCommand)
29	}
30	
31	var addCommand = &cobra.Command{
32		Use:   "add <name>",
33		Short: "Add a task to the queue",
34		Args:  cobra.ExactArgs(1),
35		RunE:  runAdd,
36	}
37	
38	func runAdd(cmd *cobra.Command, args []string) error {
39		s := store.NewMemoryStore()
40		defer s.Close()
41		return runAddWithStore(s, args[0], addCmd, addPri, addDepStr, jsonOutput, os.Stdout)
42	}
43	
44	func runAddWithStore(s store.Store, name, cmdStr string, priority int, depStr string, jsonOut bool, w io.Writer) error {
45		if cmdStr == "" {
46			return fmt.Errorf("tq: cannot add task %q: --cmd is required", name)
47		}
48	
49		var deps []string
50		if depStr != "" {
51			deps = strings.Split(depStr, ",")
52			// Validate dependencies exist
53			tasks, err := s.List(store.Filter{})
54			if err != nil {
55				return fmt.Errorf("tq: cannot add task %q: %w", name, err)
56			}
57			existing := make(map[string]bool, len(tasks))
58			for _, t := range tasks {
59				existing[t.ID] = true
60			}
61			for _, d := range deps {
62				if !existing[d] {
63					return fmt.Errorf("tq: cannot add task %q: dependency %q not found", name, d)
64				}
65			}
66		}
67	
68		state := store.StateReady
69		if len(deps) > 0 {
70			state = store.StatePending
71		}
72		if deps == nil {
73			deps = []string{}
74		}
75	
76		// Pre-generate ID
77		b := make([]byte, 4)
78		if _, err := rand.Read(b); err != nil {
79			return fmt.Errorf("tq: cannot add task %q: %w", name, err)
80		}
81		id := hex.EncodeToString(b)
82	
83		task := store.Task{
84			ID:        id,
85			Name:      name,
86			Cmd:       cmdStr,
87			State:     state,
88			Priority:  priority,
89			DependsOn: deps,
90			CreatedAt: time.Now(),
91		}
92	
93		if err := s.Add(task); err != nil {
94			return fmt.Errorf("tq: cannot add task %q: %w", name, err)
95		}
96	
97		if jsonOut {
98			return json.NewEncoder(w).Encode(struct {
99				ID string `json:"id"`
100			}{ID: id})
101		}
102		fmt.Fprintln(w, id)
103		return nil
104	}
105

1	package cmd
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"io"
7		"os"
8		"sort"
9		"strings"
10		"time"
11	
12		"tq/store"
13	
14		"github.com/spf13/cobra"
15	)
16	
17	var listState string
18	
19	func init() {
20		listCommand.Flags().StringVar(&listState, "state", "", "Filter by state (pending, ready, running, done, failed, dead)")
21		rootCmd.AddCommand(listCommand)
22	}
23	
24	var listCommand = &cobra.Command{
25		Use:   "list",
26		Short: "List tasks in the queue",
27		RunE:  runList,
28	}
29	
30	func runList(cmd *cobra.Command, args []string) error {
31		s := store.NewMemoryStore()
32		defer s.Close()
33		return runListWithStore(s, listState, jsonOutput, os.Stdout)
34	}
35	
36	// ListTask is the JSON representation of a task in list output.
37	type ListTask struct {
38		ID        string   `json:"id"`
39		Name      string   `json:"name"`
40		Cmd       string   `json:"cmd"`
41		State     string   `json:"state"`
42		Priority  int      `json:"priority"`
43		DependsOn []string `json:"depends_on"`
44		CreatedAt string   `json:"created_at"`
45	}
46	
47	func runListWithStore(s store.Store, stateStr string, jsonOut bool, w io.Writer) error {
48		var filter store.Filter
49		if stateStr != "" {
50			st := store.State(stateStr)
51			valid := false
52			for _, s := range store.AllStates {
53				if s == st {
54					valid = true
55					break
56				}
57			}
58			if !valid {
59				names := make([]string, len(store.AllStates))
60				for i, s := range store.AllStates {
61					names[i] = string(s)
62				}
63				return fmt.Errorf("tq: invalid state %q (valid: %s)", stateStr, strings.Join(names, ", "))
64			}
65			filter.State = &st
66		}
67	
68		tasks, err := s.List(filter)
69		if err != nil {
70			return fmt.Errorf("tq: cannot list tasks: %w", err)
71		}
72	
73		// Sort: priority descending, then CreatedAt ascending
74		sort.Slice(tasks, func(i, j int) bool {
75			if tasks[i].Priority != tasks[j].Priority {
76				return tasks[i].Priority > tasks[j].Priority
77			}
78			return tasks[i].CreatedAt.Before(tasks[j].CreatedAt)
79		})
80	
81		if jsonOut {
82			out := make([]ListTask, len(tasks))
83			for i, t := range tasks {
84				deps := t.DependsOn
85				if deps == nil {
86					deps = []string{}
87				}
88				out[i] = ListTask{
89					ID:        t.ID,
90					Name:      t.Name,
91					Cmd:       t.Cmd,
92					State:     string(t.State),
93					Priority:  t.Priority,
94					DependsOn: deps,
95					CreatedAt: t.CreatedAt.Format(time.RFC3339),
96				}
97			}
98			return json.NewEncoder(w).Encode(out)
99		}
100	
101		if len(tasks) == 0 {
102			return nil
103		}
104	
105		fmt.Fprintf(w, "%-10s%-10s%4s  %-16s%s\n", "ID", "STATE", "PRI", "NAME", "DEPENDS")
106		for _, t := range tasks {
107			deps := strings.Join(t.DependsOn, ",")
108			fmt.Fprintf(w, "%-10s%-10s%4d  %-16s%s\n", t.ID, t.State, t.Priority, t.Name, deps)
109		}
110		return nil
111	}
