12	func TestAddBasic(t *testing.T) {
13		s := store.NewMemoryStore()
14		var buf bytes.Buffer
15		err := runAddWithStore(s, "build", "make build", 5, "", false, &buf)
16		if err != nil {
17			t.Fatalf("unexpected error: %v", err)
18		}
19		id := strings.TrimSpace(buf.String())
20		if len(id) != 8 {
21			t.Errorf("expected 8-char hex ID, got %q", id)
22		}
23	
24		// Verify task in store
25		tasks, _ := s.List(store.Filter{})
26		if len(tasks) != 1 {
27			t.Fatalf("expected 1 task, got %d", len(tasks))
28		}
29		task := tasks[0]
30		if task.Name != "build" {
31			t.Errorf("expected name 'build', got %q", task.Name)
32		}
33		if task.Cmd != "make build" {
34			t.Errorf("expected cmd 'make build', got %q", task.Cmd)
35		}
36		if task.Priority != 5 {
37			t.Errorf("expected priority 5, got %d", task.Priority)
38		}
39		if task.State != store.StateReady {
40			t.Errorf("expected state ready, got %s", task.State)
41		}
42	}
