56	func TestAddWithDeps(t *testing.T) {
57		s := store.NewMemoryStore()
58		// Add a task to depend on
59		s.Add(store.Task{ID: "abc12345", Name: "compile", Cmd: "make", State: store.StateReady})
60	
61		var buf bytes.Buffer
62		err := runAddWithStore(s, "test", "make test", 0, "abc12345", false, &buf)
63		if err != nil {
64			t.Fatalf("unexpected error: %v", err)
65		}
66	
67		tasks, _ := s.List(store.Filter{})
68		// Find the newly added task (not "compile")
69		for _, task := range tasks {
70			if task.Name == "test" {
71				if task.State != store.StatePending {
72					t.Errorf("expected state pending (has deps), got %s", task.State)
73				}
74				if len(task.DependsOn) != 1 || task.DependsOn[0] != "abc12345" {
75					t.Errorf("expected depends-on [abc12345], got %v", task.DependsOn)
76				}
77				return
78			}
79		}
80		t.Fatal("newly added task not found in store")
81	}
