25	func TestListWithTasks(t *testing.T) {
26		s := store.NewMemoryStore()
27		s.Add(store.Task{ID: "aaaa1111", Name: "build", Cmd: "make", State: store.StateReady, Priority: 10, CreatedAt: time.Now()})
28		s.Add(store.Task{ID: "bbbb2222", Name: "test", Cmd: "make test", State: store.StatePending, Priority: 5, DependsOn: []string{"aaaa1111"}, CreatedAt: time.Now()})
29	
30		var buf bytes.Buffer
31		err := runListWithStore(s, "", false, &buf)
32		if err != nil {
33			t.Fatalf("unexpected error: %v", err)
34		}
35		out := buf.String()
36		lines := strings.Split(strings.TrimSpace(out), "\n")
37		if len(lines) != 3 {
38			t.Fatalf("expected 3 lines (header + 2 tasks), got %d:\n%s", len(lines), out)
39		}
40		// Header
41		if !strings.HasPrefix(lines[0], "ID") {
42			t.Errorf("expected header starting with ID, got: %q", lines[0])
43		}
44		// First row should be higher priority (build, pri 10)
45		if !strings.Contains(lines[1], "build") {
46			t.Errorf("expected first task to be 'build' (higher pri), got: %q", lines[1])
47		}
48		// Second row should be lower priority (test, pri 5)
49		if !strings.Contains(lines[2], "test") {
50			t.Errorf("expected second task to be 'test' (lower pri), got: %q", lines[2])
51		}
52		// Deps column
53		if !strings.Contains(lines[2], "aaaa1111") {
54			t.Errorf("expected depends column to show aaaa1111, got: %q", lines[2])
55		}
56	}
