143		s.Add(store.Task{ID: "aaaa1111", Name: "older", Cmd: "a", State: store.StateReady, Priority: 5, CreatedAt: now})
144		// Higher priority — should be first regardless of time
145		s.Add(store.Task{ID: "bbbb2222", Name: "urgent", Cmd: "b", State: store.StateReady, Priority: 10, CreatedAt: now.Add(2 * time.Minute)})
