151		if len(lines) != 4 {
152			t.Fatalf("expected 4 lines, got %d:\n%s", len(lines), buf.String())
153		}
154		// First data row: urgent (pri 10)
155		if !strings.Contains(lines[1], "urgent") {
156			t.Errorf("expected first task 'urgent' (highest pri), got: %q", lines[1])
157		}
158		// Second: older (pri 5, earlier time)
159		if !strings.Contains(lines[2], "older") {
160			t.Errorf("expected second task 'older' (same pri, earlier), got: %q", lines[2])
161		}
162		// Third: newer (pri 5, later time)
163		if !strings.Contains(lines[3], "newer") {
164			t.Errorf("expected third task 'newer' (same pri, later), got: %q", lines[3])
165		}
