2	
3	import (
4		"encoding/json"
5		"fmt"
6		"io"
7		"os"
8		"sort"
9		"strings"
10		"time"
11	
12		"tq/store"
13	
14		"github.com/spf13/cobra"
15	)
16	
17	var listState string
18	
19	func init() {
20		listCommand.Flags().StringVar(&listState, "state", "", "Filter by state (pending, ready, running, done, failed, dead)")
21		rootCmd.AddCommand(listCommand)
22	}
23	
24	var listCommand = &cobra.Command{
25		Use:   "list",
26		Short: "List tasks in the queue",
27		RunE:  runList,
28	}
29	
30	func runList(cmd *cobra.Command, args []string) error {
31		s := store.NewMemoryStore()
32		defer s.Close()
33		return runListWithStore(s, listState, jsonOutput, os.Stdout)
34	}
35	
36	// ListTask is the JSON representation of a task in list output.
37	type ListTask struct {
38		ID        string   `json:"id"`
39		Name      string   `json:"name"`
40		Cmd       string   `json:"cmd"`
41		State     string   `json:"state"`
42		Priority  int      `json:"priority"`
43		DependsOn []string `json:"depends_on"`
44		CreatedAt string   `json:"created_at"`
45	}
46	
47	func runListWithStore(s store.Store, stateStr string, jsonOut bool, w io.Writer) error {
48		var filter store.Filter
49		if stateStr != "" {
50			st := store.State(stateStr)
51			valid := false
52			for _, s := range store.AllStates {
53				if s == st {
54					valid = true
55					break
56				}
57			}
58			if !valid {
59				names := make([]string, len(store.AllStates))
60				for i, s := range store.AllStates {
61					names[i] = string(s)
62				}
63				return fmt.Errorf("tq: invalid state %q (valid: %s)", stateStr, strings.Join(names, ", "))
64			}
65			filter.State = &st
66		}
67	
68		tasks, err := s.List(filter)
69		if err != nil {
70			return fmt.Errorf("tq: cannot list tasks: %w", err)
71		}
72	
73		// Sort: priority descending, then CreatedAt ascending
74		sort.Slice(tasks, func(i, j int) bool {
75			if tasks[i].Priority != tasks[j].Priority {
76				return tasks[i].Priority > tasks[j].Priority
77			}
78			return tasks[i].CreatedAt.Before(tasks[j].CreatedAt)
79		})
80	
81		if jsonOut {
82			out := make([]ListTask, len(tasks))
83			for i, t := range tasks {
84				deps := t.DependsOn
85				if deps == nil {
86					deps = []string{}
87				}
88				out[i] = ListTask{
89					ID:        t.ID,
90					Name:      t.Name,
91					Cmd:       t.Cmd,
92					State:     string(t.State),
93					Priority:  t.Priority,
94					DependsOn: deps,
95					CreatedAt: t.CreatedAt.Format(time.RFC3339),
96				}
97			}
98			return json.NewEncoder(w).Encode(out)
99		}
100	
101		if len(tasks) == 0 {
102			return nil
103		}
104	
105		fmt.Fprintf(w, "%-10s%-10s%4s  %-16s%s\n", "ID", "STATE", "PRI", "NAME", "DEPENDS")
106		for _, t := range tasks {
107			deps := strings.Join(t.DependsOn, ",")
108			fmt.Fprintf(w, "%-10s%-10s%4d  %-16s%s\n", t.ID, t.State, t.Priority, t.Name, deps)
109		}
110		return nil
111	}
