1	package store
2	
3	import (
4		"crypto/rand"
5		"encoding/hex"
6		"sync"
7	)
8	
9	// MemoryStore is an in-memory Store implementation.
10	type MemoryStore struct {
11		mu    sync.Mutex
12		tasks map[string]Task
13	}
14	
15	// NewMemoryStore returns an empty MemoryStore.
16	func NewMemoryStore() *MemoryStore {
17		return &MemoryStore{tasks: make(map[string]Task)}
18	}
19	
20	// Add inserts a task. If task.ID is empty, a random ID is generated.
21	func (m *MemoryStore) Add(task Task) error {
22		m.mu.Lock()
23		defer m.mu.Unlock()
24		if task.ID == "" {
25			b := make([]byte, 4)
26			if _, err := rand.Read(b); err != nil {
27				return err
28			}
29			task.ID = hex.EncodeToString(b)
30		}
31		m.tasks[task.ID] = task
32		return nil
33	}
34	
35	// List returns tasks matching the filter. Returns a copy, not internal references.
36	func (m *MemoryStore) List(filter Filter) ([]Task, error) {
37		m.mu.Lock()
38		defer m.mu.Unlock()
39		var result []Task
40		for _, t := range m.tasks {
41			if filter.State != nil && t.State != *filter.State {
42				continue
43			}
44			result = append(result, t)
45		}
46		return result, nil
47	}
48	
49	// Close is a no-op for MemoryStore.
50	func (m *MemoryStore) Close() error {
51		return nil
52	}
